CREATE TABLE `attendance_snapshots` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `payroll_batch_id` bigint(20) unsigned NOT NULL,
  `employee_id` bigint(20) unsigned NOT NULL,
  `days_present` decimal(5,3) NOT NULL DEFAULT 0.000 COMMENT 'Working days actually present',
  `lwop_days` decimal(5,3) NOT NULL DEFAULT 0.000 COMMENT 'Leave Without Pay days (after leave credits exhausted)',
  `late_minutes` smallint(5) unsigned NOT NULL DEFAULT 0 COMMENT 'Cumulative late minutes for the cut-off',
  `undertime_minutes` smallint(5) unsigned NOT NULL DEFAULT 0 COMMENT 'Cumulative undertime minutes for the cut-off',
  `is_corrected` tinyint(1) NOT NULL DEFAULT 0,
  `correction_note` text DEFAULT NULL,
  `corrected_by` bigint(20) unsigned DEFAULT NULL,
  `corrected_at` timestamp NULL DEFAULT NULL,
  `source` enum('hris_api','manual') NOT NULL DEFAULT 'hris_api',
  `fetched_at` timestamp NULL DEFAULT NULL COMMENT 'When the HRIS API was last called for this record',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_attendance_batch_employee` (`payroll_batch_id`,`employee_id`),
  KEY `attendance_snapshots_corrected_by_foreign` (`corrected_by`),
  KEY `attendance_snapshots_employee_id_index` (`employee_id`),
  KEY `attendance_snapshots_payroll_batch_id_is_corrected_index` (`payroll_batch_id`,`is_corrected`),
  CONSTRAINT `attendance_snapshots_corrected_by_foreign` FOREIGN KEY (`corrected_by`) REFERENCES `users` (`id`) ON DELETE SET NULL,
  CONSTRAINT `attendance_snapshots_employee_id_foreign` FOREIGN KEY (`employee_id`) REFERENCES `employees` (`id`),
  CONSTRAINT `attendance_snapshots_payroll_batch_id_foreign` FOREIGN KEY (`payroll_batch_id`) REFERENCES `payroll_batches` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=247 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
